    #[test]
    fn test_basic_creation_and_access() {
        let cell = ConcurrentCell::new(42i32);
        let guard = cell.try_get().unwrap();
        unsafe {
            assert_eq!(*guard.as_ref(), 42);
        }
        drop(guard);
        assert_eq!(cell.active_refs(), 0);
    }

    #[test]
    fn test_multiple_concurrent_guards() {
        let cell = ConcurrentCell::with_max_refs(AtomicI64::new(0), 4);
        let g1 = cell.try_get().unwrap();
        let g2 = cell.try_get().unwrap();
        let g3 = cell.try_get().unwrap();
        let g4 = cell.try_get().unwrap();

        assert_eq!(cell.active_refs(), 4);

        // Fifth should fail
        let result = cell.try_get();
        assert!(result.is_err());
        assert_eq!(
            result.unwrap_err(),
            ConcurrentCellError::TooManyConcurrentAccessors {
                current: 4,
                max: 4
            }
        );

        drop(g1);
        assert_eq!(cell.active_refs(), 3);

        // Now we can get another
        let _g5 = cell.try_get().unwrap();
        assert_eq!(cell.active_refs(), 4);

        drop(g2);
        drop(g3);
        drop(g4);
        drop(_g5);
        assert_eq!(cell.active_refs(), 0);
    }

    #[test]
    fn test_concurrent_atomic_access() {
        let cell = Arc::new(ConcurrentCell::new(AtomicI64::new(0)));
        let num_threads = 8;
        let iterations = 10_000;

        let handles: Vec<_> = (0..num_threads)
            .map(|_| {
                let cell = Arc::clone(&cell);
                thread::spawn(move || {
                    for _ in 0..iterations {
                        if let Ok(guard) = cell.try_get() {
                            unsafe {
                                guard.as_ref().fetch_add(1, Ordering::Relaxed);
                            }
                        }
                    }
                })
            })
            .collect();

        for handle in handles {
            handle.join().unwrap();
        }

        let guard = cell.try_get().unwrap();
        let final_value = unsafe { guard.as_ref().load(Ordering::SeqCst) };
        assert_eq!(final_value, (num_threads * iterations) as i64);
    }

