    #[test]
    fn test_concurrent_vec_concurrent_access() {
        let vec = Arc::new(ConcurrentVec::<AtomicI64>::new(16).unwrap());

        // Initialize all slots
        for i in 0..16 {
            unsafe {
                vec.set(i, AtomicI64::new(0)).unwrap();
            }
        }

        let num_threads = 4;
        let iterations = 1_000;

        let handles: Vec<_> = (0..num_threads)
            .map(|thread_id| {
                let vec = Arc::clone(&vec);
                thread::spawn(move || {
                    for _ in 0..iterations {
                        // Each thread works on its own slot
                        let index = thread_id % 16;
                        if let Some(guard) = vec.try_get(index) {
                            unsafe {
                                if let Some(ref atomic) = *guard.as_ref() {
                                    atomic.fetch_add(1, Ordering::Relaxed);
                                }
                            }
                        }
                    }
                })
            })
            .collect();

        for handle in handles {
            handle.join().unwrap();
        }

        // Verify results
        for i in 0..num_threads {
            let index = i % 16;
            if let Some(guard) = vec.try_get(index) {
                unsafe {
                    if let Some(ref atomic) = *guard.as_ref() {
                        let count = atomic.load(Ordering::SeqCst);
                        assert!(count > 0, "Slot {} should have been incremented", index);
                    }
                }
            }
        }
    }
